var gearSets = GearsetManager.GearSets.Where(i => i.InUse && (int)i.Class is 19 or 21 or 32 or 37).ToList().OrderByDescending(i=> i.Gear.First().Item.ItemLevel);

if (gearSets.Any())
{
    gearSets.First().Activate();
    await Coroutine.Sleep(2000);
}


